class Solution:
    def firstUniqChar(self, s):
        for i, ch in enumerate(s):
            if s.index(ch) == s.rindex(ch):
                return i
        return -1

solutions.python:
class Solution:
    def firstUniqChar(self, s):
        from collections import Counter
        counts = Counter(s)
        for i, ch in enumerate(s):
            if counts[ch] == 1:
                return i
        return -1

