var firstUniqChar = function(s) {
    const counts = new Map();
    for (const ch of s) counts.set(ch, (counts.get(ch) || 0) + 1);
    for (let i = 0; i < s.length; i++) {
        if (counts.get(s[i]) === 1) return i;
    }
